import anthropic
import sqlite3
import json
from typing import Any


def run_sql(db_path: str, query: str) -> list[dict]:
    """Execute a SQL query and return results as a list of dicts."""
    conn = sqlite3.connect(db_path)
    conn.row_factory = sqlite3.Row
    try:
        cursor = conn.execute(query)
        rows = [dict(row) for row in cursor.fetchall()]
        return rows
    finally:
        conn.close()


def summarise_results(rows: list[dict], max_rows: int = 50) -> str:
    """Convert query results to a compact text summary for the LLM."""
    if not rows:
        return "Query returned no results."
    columns = list(rows[0].keys())
    header = " | ".join(columns)
    divider = "-" * len(header)
    data_lines = [" | ".join(str(row[c]) for c in columns) for row in rows[:max_rows]]
    suffix = f"\n(showing {max_rows} of {len(rows)} rows)" if len(rows) > max_rows else ""
    return f"{header}\n{divider}\n" + "\n".join(data_lines) + suffix


SCHEMA_CONTEXT = """
Available tables:
- orders(order_id, customer_id, created_at DATE, product_id, quantity, unit_price, status)
- customers(customer_id, name, segment TEXT, region TEXT, created_at DATE)
- products(product_id, name, category, cost_price)

KPI definitions:
- revenue = SUM(quantity * unit_price) WHERE status != 'cancelled'
- gross_margin = (revenue - SUM(quantity * cost_price)) / revenue
- customer_segment values: 'enterprise', 'mid-market', 'smb'
"""

TOOLS = [
    {
        "name": "run_query",
        "description": "Execute a read-only SQL query against the business database. Returns row data.",
        "input_schema": {
            "type": "object",
            "properties": {
                "sql": {
                    "type": "string",
                    "description": "A valid SQLite SELECT query. Must be read-only — no INSERT, UPDATE, DELETE."
                },
                "explanation": {
                    "type": "string",
                    "description": "One-sentence explanation of what this query computes."
                }
            },
            "required": ["sql", "explanation"]
        }
    }
]


def bi_agent(question: str, db_path: str) -> dict[str, Any]:
    """Answer a business question by querying the database."""
    client = anthropic.Anthropic()
    messages = [
        {
            "role": "user",
            "content": f"""{SCHEMA_CONTEXT}

Answer the following business question using SQL queries. Run queries as needed,
then provide a clear narrative answer.

Question: {question}"""
        }
    ]

    query_log = []

    # Agentic loop: LLM decides when to call tools and when to stop
    while True:
        response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=2048,
            tools=TOOLS,
            messages=messages,
        )

        # Collect any tool calls
        tool_results = []
        for block in response.content:
            if block.type == "tool_use" and block.name == "run_query":
                sql = block.input["sql"]
                explanation = block.input.get("explanation", "")
                try:
                    rows = run_sql(db_path, sql)
                    result_text = summarise_results(rows)
                    query_log.append({"sql": sql, "explanation": explanation, "rows_returned": len(rows)})
                except Exception as exc:
                    result_text = f"Query error: {exc}"
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result_text
                })

        # If no tool calls, the model is done
        if response.stop_reason == "end_turn" or not tool_results:
            # Extract the final text answer
            final_text = next(
                (b.text for b in response.content if hasattr(b, "text")),
                "No answer generated."
            )
            return {"answer": final_text, "queries_run": query_log}

        # Feed tool results back and continue
        messages.append({"role": "assistant", "content": response.content})
        messages.append({"role": "user", "content": tool_results})
